module Account::Reportable
  extend ActiveSupport::Concern

  def monthly_report
    {
      invoices: invoices.where(created_at: 30.days.ago..).map { |i| i.line_items.sum(&:amount) },
      projects: projects.includes(:recordings).flat_map { |p| p.recordings.map(&:recordable) },
      users: users.includes(:profile, :sessions).map { |u| u.sessions.last&.created_at }
    }
  end
end
